// Parse incoming WhatsApp Cloud API webhook - v16 (Direct WA)
const raw = $input.first().json;
const body = raw.body || raw || {};

// WhatsApp Cloud API structure:
// body.entry[0].changes[0].value.messages[0]
// body.entry[0].changes[0].value.contacts[0]

let message = '';
let waId = '';
let firstName = 'amigo';
let phone = '';
let isAudio = false;
let audioMediaId = '';
let isImage = false;
let imageMediaId = '';
let messageType = 'text';
let externalMessageId = '';
let whatsappPhoneNumberId = '';

try {
  const entry = body.entry?.[0];
  const change = entry?.changes?.[0];
  const value = change?.value || {};

  // Check if this is a status update (not a message)
  if (!value.messages || value.messages.length === 0) {
    return [{ json: { is_status_update: true, skip: true } }];
  }

  const msg = value.messages[0];
  const contact = value.contacts?.[0] || {};

  waId = msg.from || contact.wa_id || '';
  firstName = contact.profile?.name?.split(' ')[0] || 'amigo';
  phone = waId;
  messageType = msg.type || 'text';
  externalMessageId = msg.id || '';
  whatsappPhoneNumberId = value.metadata?.phone_number_id || '';

  if (messageType === 'text') {
    message = msg.text?.body || '';
  } else if (messageType === 'audio') {
    isAudio = true;
    audioMediaId = msg.audio?.id || '';
    message = ''; // will be filled after transcription
  } else if (messageType === 'image') {
    isImage = true;
    imageMediaId = msg.image?.id || '';
    message = msg.image?.caption || '(imagen)';
  } else if (messageType === 'document') {
    message = msg.document?.caption || '(documento)';
  } else if (messageType === 'sticker') {
    message = '(sticker)';
  } else if (messageType === 'reaction') {
    message = '(reacción)';
  } else if (messageType === 'location') {
    message = 'Ubicación: ' + (msg.location?.latitude || '') + ',' + (msg.location?.longitude || '');
  } else if (messageType === 'interactive') {
    message = msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '(interactivo)';
  } else {
    message = '(tipo no soportado: ' + messageType + ')';
  }
} catch (e) {
  return [{ json: { is_status_update: true, skip: true, error: e.message } }];
}

const isEmpty = !message && !isAudio;

// Phone area code detection (same as v15)
const normalizePhoneDigits = (value) => {
  let digits = String(value || '').replace(/\D+/g, '');
  if (digits.startsWith('54')) digits = digits.slice(2);
  if (digits.startsWith('9')) digits = digits.slice(1);
  if (digits.startsWith('0')) digits = digits.slice(1);
  return digits;
};

const PHONE_AREA_CODES = [
  { code: '3718', name: 'Clorinda', province: 'Formosa' },
  { code: '3873', name: 'Tartagal', province: 'Salta' },
  { code: '3492', name: 'Rafaela', province: 'Santa Fe' },
  { code: '3489', name: 'Campana / Zarate', province: 'Buenos Aires' },
  { code: '3482', name: 'Reconquista', province: 'Santa Fe' },
  { code: '3878', name: 'Oran', province: 'Salta' },
  { code: '3876', name: 'Metan', province: 'Salta' },
  { code: '3865', name: 'Concepcion', province: 'Tucuman' },
  { code: '3858', name: 'Termas de Rio Hondo', province: 'Santiago del Estero' },
  { code: '3757', name: 'Puerto Iguazu', province: 'Misiones' },
  { code: '3755', name: 'Obera', province: 'Misiones' },
  { code: '3777', name: 'Goya', province: 'Corrientes' },
  { code: '3564', name: 'San Francisco', province: 'Cordoba' },
  { code: '3541', name: 'Villa Carlos Paz', province: 'Cordoba' },
  { code: '353', name: 'Villa Maria', province: 'Cordoba' },
  { code: '364', name: 'Presidencia Roque Saenz Pena', province: 'Chaco' },
  { code: '358', name: 'Rio Cuarto', province: 'Cordoba' },
  { code: '345', name: 'Concordia', province: 'Entre Rios' },
  { code: '343', name: 'Parana', province: 'Entre Rios' },
  { code: '342', name: 'Santa Fe', province: 'Santa Fe' },
  { code: '341', name: 'Rosario', province: 'Santa Fe' },
  { code: '3888', name: 'San Pedro de Jujuy', province: 'Jujuy' },
  { code: '3885', name: 'La Quiaca', province: 'Jujuy' },
  { code: '387', name: 'Salta', province: 'Salta' },
  { code: '388', name: 'San Salvador de Jujuy', province: 'Jujuy' },
  { code: '385', name: 'Santiago del Estero', province: 'Santiago del Estero' },
  { code: '383', name: 'San Fernando del Valle de Catamarca', province: 'Catamarca' },
  { code: '381', name: 'San Miguel de Tucuman', province: 'Tucuman' },
  { code: '380', name: 'La Rioja', province: 'La Rioja' },
  { code: '379', name: 'Corrientes', province: 'Corrientes' },
  { code: '376', name: 'Posadas', province: 'Misiones' },
  { code: '370', name: 'Formosa', province: 'Formosa' },
  { code: '362', name: 'Resistencia', province: 'Chaco' },
  { code: '351', name: 'Cordoba', province: 'Cordoba' },
  { code: '336', name: 'San Nicolas', province: 'Buenos Aires' },
  { code: '299', name: 'Neuquen', province: 'Neuquen' },
  { code: '298', name: 'General Roca / Alto Valle', province: 'Rio Negro' },
  { code: '297', name: 'Comodoro Rivadavia', province: 'Chubut' },
  { code: '2966', name: 'Rio Gallegos', province: 'Santa Cruz' },
  { code: '2954', name: 'Santa Rosa', province: 'La Pampa' },
  { code: '294', name: 'Bariloche / Patagonia Andina', province: 'Rio Negro' },
  { code: '291', name: 'Bahia Blanca', province: 'Buenos Aires' },
