  { code: '261', name: 'Mendoza', province: 'Mendoza' },
  { code: '260', name: 'San Rafael', province: 'Mendoza' },
  { code: '249', name: 'Tandil', province: 'Buenos Aires' },
  { code: '236', name: 'Junin', province: 'Buenos Aires' },
  { code: '2302', name: 'General Pico', province: 'La Pampa' },
  { code: '223', name: 'Mar del Plata', province: 'Buenos Aires' },
  { code: '221', name: 'La Plata', province: 'Buenos Aires' },
  { code: '11', name: 'AMBA / CABA', province: 'CABA' },
].sort((a, b) => b.code.length - a.code.length);

const inferArea = (ph) => {
  const digits = normalizePhoneDigits(ph);
  if (!digits) return { phone_digits: '', phone_area_code: '', phone_area_name: '', phone_area_province: '', phone_location_hint: 'unknown' };
  const match = PHONE_AREA_CODES.find((item) => digits.startsWith(item.code));
  if (!match) return { phone_digits: digits, phone_area_code: '', phone_area_name: '', phone_area_province: '', phone_location_hint: 'unknown_area' };
  return {
    phone_digits: digits,
    phone_area_code: match.code,
    phone_area_name: match.name,
    phone_area_province: match.province,
    phone_location_hint: match.province === 'Salta' ? 'salta_area' : 'phone_area_known',
  };
};

const area = inferArea(phone);

return [{
  json: {
    wa_id: waId,
    subscriber_id: waId,  // compatibility alias
    channel: 'whatsapp_cloud',
    external_message_id: externalMessageId,
    whatsapp_phone_number_id: whatsappPhoneNumberId,
    first_name: firstName,
    last_name: '',
    phone: phone,
    timezone: '',
    subscribed_at: '',
    city: '',
    funnel_stage: '',
    interested_product: '',
    is_human_active: false,  // will be checked via Supabase
    raw_message: message,
    is_audio: isAudio,
    audio_media_id: audioMediaId,
    is_image: isImage,
    image_media_id: imageMediaId,
    message_type: messageType,
    is_empty: isEmpty,
    is_salta_phone: area.phone_area_province === 'Salta',
    phone_location_hint: area.phone_location_hint,
    phone_area_code: area.phone_area_code,
    phone_area_name: area.phone_area_name,
    phone_area_province: area.phone_area_province,
  }
}];

// Merge: audio transcription or text input – v16
const detectData = $('Parse Input').first().json;
let userMessage, wasAudio;

try {
  const whisperOutput = $('Groq Whisper Transcribe').first().json;
  userMessage = whisperOutput.text || 'No pude entender el audio.';
  wasAudio = true;
} catch(e) {
  userMessage = detectData.raw_message;
  wasAudio = false;
}

return [{
  json: {
    ...detectData,
    user_message: userMessage,
    was_audio: wasAudio
  }
}];

const data = $input.first().json;
await new Promise((resolve) => setTimeout(resolve, 8000));
return [{ json: data }];

