// DEBOUNCE CHECK v15 - Atomic latest-message validation
const mergedData = $('Merge Input').first().json;
const saveNode = $('Save Incoming Message').first();

let ourId = null;
const savedBody = saveNode.json;

if (Array.isArray(savedBody)) {
  if (savedBody.length > 0 && savedBody[0]?.id !== undefined) {
    ourId = savedBody[0].id;
  }
} else if (savedBody && typeof savedBody === 'object') {
  if (savedBody.id !== undefined) {
    ourId = savedBody.id;
  }
}

if (ourId === null || ourId === undefined) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'duplicate_or_missing_saved_message_id' } }];
}

const rpcResult = $('Check Is Latest (RPC)').first().json;

let isLatest = false;
if (typeof rpcResult === 'boolean') {
  isLatest = rpcResult;
} else if (Array.isArray(rpcResult) && rpcResult.length > 0) {
  isLatest = rpcResult[0] === true || rpcResult[0]?.check_is_latest_message === true;
} else if (rpcResult && typeof rpcResult === 'object') {
  isLatest = rpcResult.check_is_latest_message === true || rpcResult.result === true;
}

if (!isLatest) {
  return [{ json: { ...mergedData, should_continue: false, debug: 'not_latest' } }];
}

return [{ json: { ...mergedData, should_continue: true, our_id: ourId } }];

// MERGE & AGGREGATE consecutive user bursts v15
const mergedData = $('Debounce Check').first().json;

let recentRaw = [];
try {
  recentRaw = $('Fetch Recent Messages').all();
} catch (e) {
  recentRaw = [];
}

const byId = new Map();
for (const item of recentRaw) {
  const payload = item.json;
  const rows = Array.isArray(payload) ? payload : [payload];
  for (const row of rows) {
    if (!row || row.id === undefined || row.id === null) continue;
    byId.set(row.id, row);
  }
}

const recentMessages = [...byId.values()]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));

if (recentMessages.length === 0) {
  return [{ json: { ...mergedData, messages_merged: 1 } }];
}

const latestId = mergedData.our_id;
let latestIndex = recentMessages.findIndex((row) => String(row.id) === String(latestId));
if (latestIndex === -1) latestIndex = recentMessages.length - 1;

const burst = [];
for (let i = latestIndex; i >= 0; i--) {
  const row = recentMessages[i];
  if (!row || row.role !== 'user') break;
  const text = String(row.message || '').trim();
  if (text && text !== '(vacío)') burst.unshift(text);
}

const combined = burst.join(' ').trim();

return [{
  json: {
    ...mergedData,
    user_message: combined || mergedData.user_message,
    messages_merged: Math.max(burst.length, 1)
  }
}];

const rows = [];
for (const item of $input.all()) {
  const data = item.json;
  if (Array.isArray(data)) rows.push(...data);
  else if (data && data.role && data.message) rows.push(data);
}
return [{ json: { history_rows: rows } }];

const rows = [];
for (const item of $input.all()) {
  let data = item.json;
  if (data && data.data && Array.isArray(data.data)) data = data.data;
  if (Array.isArray(data)) rows.push(...data);
  else if (data && data.product_key) rows.push(data);
}
return [{ json: { products: rows } }];

// Orchestrator v16 - AI-first compact inventory context
if ($input.context.itemIndex > 0) return [];

const merged = $('Merge & Aggregate Messages').first().json;

const getNodeObject = (nodeName) => {
  try {
    const raw = $(nodeName).first().json;
    if (Array.isArray(raw)) return raw[0] || {};
    return raw && typeof raw === 'object' ? raw : {};
  } catch (error) {
    return {};
  }
};

const getNodeArray = (nodeName, key) => {
  try {
    const raw = $(nodeName).first().json?.[key];
    return Array.isArray(raw) ? raw : [];
  } catch (error) {
    return [];
  }
};

const customerData = getNodeObject('Fetch Customer Profile');
const historyRows = getNodeArray('Aggregate Conversation History', 'history_rows');
const productRows = getNodeArray('Aggregate Product Catalog', 'products');
const storeSettings = getNodeObject('Fetch Store Settings');
const stickerRows = getNodeArray('Aggregate Stickers', 'stickers');

const productImages = {};
const productKeyNameMap = {};
const productStockMap = {};
const productConditionMap = {};

const normalize = (value) => String(value || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s_-]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const unique = (arr) => [...new Set(arr.filter(Boolean))];
const hasDigits = (token) => /[a-z]*\d+[a-z]*/.test(token);
const compactMoney = (value) => {
  const num = Number(value);
  return Number.isFinite(num) ? '$' + num.toLocaleString('es-AR') : null;
};
const normalizeCategory = (value) => {
  const raw = String(value || 'GENERAL').trim();
  const norm = normalize(raw);
  if (/iphone|ios/.test(norm)) return 'IPHONE';
  if (/samsung/.test(norm)) return 'SAMSUNG';
  if (/redmi|poco|xiaomi/.test(norm)) return 'REDMI/POCO';
  return raw.toUpperCase();
};
const getAvailability = (p) => {
  const inStockNow = p.in_stock === true;
  const onOrder = String(p.delivery_type || '').trim().toLowerCase() === 'on_order';
  const deliveryDays = Number(p.delivery_days || 0);
  if (inStockNow) return { code: 'available_now', label: 'disponible ahora', sortWeight: 3 };
  if (onOrder) return { code: 'on_order', label: 'a pedido ' + deliveryDays + 'd', sortWeight: 2 };
  return { code: 'out_of_stock', label: 'sin stock', sortWeight: 1 };
};

const buildDisplayName = (p) => {
  const baseName = String(p.product_name || p.product_key || '').trim();
  const cond = String(p.condition || 'new').trim().toLowerCase();
  const variantBits = [];
  if (cond === 'used') variantBits.push('seminuevo');
  else if (cond === 'like_new') variantBits.push('como nuevo');
  else if (cond === 'refurbished') variantBits.push('reacondicionado');
  else variantBits.push('nuevo');
  if (p.battery_health) variantBits.push('bat ' + p.battery_health + '%');
  return baseName + (variantBits.length ? ' (' + variantBits.join(', ') + ')' : '');
};

const buildShortExample = (p) => {
  const bits = [String(p.product_name || '').trim()];
  if (p.storage_gb) bits.push(p.storage_gb + 'GB');
  if (p.color) bits.push(String(p.color).trim());
  return bits.filter(Boolean).join(' ');
};

const buildProductLine = (p) => {
  const specs = [
    p.ram_gb ? p.ram_gb + 'GB RAM' : '',
    p.storage_gb ? p.storage_gb + 'GB' : '',
    p.color || '',
    p.network ? String(p.network).toUpperCase() : '',
  ].filter(Boolean).join(' | ');
  const price = compactMoney(p.price_ars) || 'sin precio';
  const promo = p.promo_price_ars ? ' promo:' + compactMoney(p.promo_price_ars) : '';
  const battery = p.battery_health ? ' bat:' + p.battery_health + '%' : '';
  const cuotas = [
    p.bancarizada_cuota ? ' banc:' + compactMoney(p.bancarizada_cuota) : '',
    p.macro_cuota ? ' macro:' + compactMoney(p.macro_cuota) : '',
  ].filter(Boolean).join('');
  const availability = getAvailability(p).label;

  return '- ' + String(p.product_key || '').trim() + ' | ' + String(p.product_name || '').trim() + ' | ' + String(p.condition || 'new') + ' | ' + (specs || 'sin specs') + ' | ' + price + promo + battery + cuotas + ' | disponibilidad:' + availability;
};

for (const p of productRows) {
  if (!p || !p.product_key) continue;
  const productKey = String(p.product_key).trim();
  productKeyNameMap[productKey] = buildDisplayName(p);
  productStockMap[productKey] = p.in_stock;
  productConditionMap[productKey] = String(p.condition || 'new').trim().toLowerCase();

  const imageUrl = String(p.image_url || p.image || p.url || '').trim();
  if (imageUrl.startsWith('http')) productImages[productKey] = imageUrl;
}

const storeInfo = {
  address: String(storeSettings.store_address || 'Caseros 1365, Salta Capital').trim(),
  hours: String(storeSettings.store_hours || 'Lun-Vie 10-13 y 18-21 | Sab 10-13').trim(),
  paymentMethods: String(storeSettings.store_payment_methods || 'Transferencia, Mercado Pago, efectivo, cripto, tarjetas').trim(),
  creditPolicy: String(storeSettings.store_credit_policy || '6 cuotas presenciales en Salta Capital').trim(),
  shippingPolicy: String(storeSettings.store_shipping_policy || 'Envios y despacho segun destino').trim(),
  warrantyNew: String(storeSettings.store_warranty_new || '1 ano de garantia oficial').trim(),
  warrantyUsed: String(storeSettings.store_warranty_used || 'Garantia propia TechnoStore').trim(),
  supportedCards: String(storeSettings.customer_cards_supported || 'macro,naranja,visa,mastercard,amex,cabal').trim(),
  blockedCards: String(storeSettings.customer_cards_blocked || 'subcredito').trim(),
};

if (customerData.human_assigned === true) return [];

const userMessage = String(merged.user_message || '').trim();
const trackedProduct = String(customerData.interested_product || merged.interested_product || '').trim();
const currentStage = String(customerData.funnel_stage || merged.funnel_stage || '').trim().toLowerCase();
const profileCity = String(customerData.city || merged.city || '').trim();
const phoneAreaCode = String(merged.phone_area_code || customerData.phone_area_code || '').trim();
const phoneAreaName = String(merged.phone_area_name || customerData.phone_area_name || '').trim();
const phoneAreaProvince = String(merged.phone_area_province || customerData.phone_area_province || '').trim();
const phoneLocationText = phoneAreaCode
  ? 'indicativo ' + phoneAreaCode + ' => ' + phoneAreaName + (phoneAreaProvince ? ', ' + phoneAreaProvince : '')
  : 'sin pista confiable';
const shouldAskLocation = !profileCity;

const recentHistoryRows = [...historyRows]
  .sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0))
  .slice(-4);
const recentContextText = normalize(recentHistoryRows.map((row) => String(row.message || '')).join(' '));
const tokenSource = unique([
  normalize(userMessage),
  recentContextText,
  normalize(trackedProduct),
  normalize(customerData.preferred_brand || ''),
]).join(' ');
const tokens = unique(tokenSource
  .split(/\s+/)
  .map((token) => token.trim())
  .filter((token) => token.length >= 3 || hasDigits(token)))
  .slice(0, 32);

const rankedProducts = productRows
  .map((p) => {
    const keyNorm = normalize(p.product_key);
    const nameNorm = normalize(p.product_name);
    const categoryNorm = normalizeCategory(p.category);
    const availability = getAvailability(p);
    let score = 0;

    if (trackedProduct && p.product_key === trackedProduct) score += 140;
    for (const token of tokens) {
      if (!token) continue;
      if (keyNorm.includes(token)) score += hasDigits(token) ? 18 : 8;
      if (nameNorm.includes(token)) score += hasDigits(token) ? 16 : 6;
      if (categoryNorm.includes(token.toUpperCase())) score += 5;
    }
    score += availability.sortWeight * 3;

    return { ...p, score, normalized_category: categoryNorm, availability };
  })
  .sort((a, b) => (
    b.score - a.score
  ) || (
    b.availability.sortWeight - a.availability.sortWeight
  ) || (
    Number(a.price_ars || 0) - Number(b.price_ars || 0)
  ));

const groupedCatalog = new Map();
for (const item of rankedProducts) {
  const groupKey = item.normalized_category || 'GENERAL';
  const bucket = groupedCatalog.get(groupKey) || { category: groupKey, total: 0, availableNow: 0, onOrder: 0, examples: [] };
  bucket.total += 1;
  if (item.availability.code === 'available_now') bucket.availableNow += 1;
  if (item.availability.code === 'on_order') bucket.onOrder += 1;
  const example = buildShortExample(item);
  if (example && bucket.examples.length < 2 && !bucket.examples.includes(example)) bucket.examples.push(example);
  groupedCatalog.set(groupKey, bucket);
}

const catalogGroups = [...groupedCatalog.values()]
  .sort((a, b) => (b.availableNow + b.onOrder) - (a.availableNow + a.onOrder) || b.total - a.total || a.category.localeCompare(b.category))
  .slice(0, 6);

const totals = rankedProducts.reduce((acc, item) => {
  if (item.availability.code === 'available_now') acc.availableNow += 1;
  else if (item.availability.code === 'on_order') acc.onOrder += 1;
  else acc.outOfStock += 1;
  return acc;
}, { availableNow: 0, onOrder: 0, outOfStock: 0 });

const catalogSummaryText = [
  'total modelos: ' + productRows.length + ' | disponible ahora: ' + totals.availableNow + ' | a pedido: ' + totals.onOrder,
  ...catalogGroups.map((group) => '- ' + group.category + ': ahora ' + group.availableNow + ' | a pedido ' + group.onOrder + ' | total ' + group.total + '. Ej: ' + (group.examples.join(', ') || 'sin ejemplo')),
].join('\n');

const asksBroadCatalog = /(catalogo|lista completa|ver todo|mostrar todo|todos los|que tienen|que hay|equipos|celus|celu|phones|telefonos|celulares)/.test(normalize(userMessage));
const focusedCandidates = rankedProducts.filter((item) => item.score > 0 || item.product_key === trackedProduct);
let candidateProducts = [];
let inventoryMode = 'sample';

if (focusedCandidates.length > 0) {
  inventoryMode = 'focused';
  if (asksBroadCatalog) {
    const grouped = new Map();
    for (const item of focusedCandidates) {
      const key = item.normalized_category || 'GENERAL';
      const list = grouped.get(key) || [];
      if (list.length < 3) list.push(item);
      grouped.set(key, list);
    }
    candidateProducts = [...grouped.values()].flat().slice(0, 15);
  } else {
    candidateProducts = focusedCandidates.slice(0, 8);
  }
} else {
  const fallback = [];
  for (const group of catalogGroups) {
    const matches = rankedProducts.filter((item) => item.normalized_category === group.category).slice(0, 2);
    fallback.push(...matches);
  }
  candidateProducts = unique(fallback).slice(0, 8);
}

const historyText = recentHistoryRows.length > 0
  ? recentHistoryRows.map((row) => {
      const role = row.role === 'user' ? 'U' : row.role === 'bot' ? 'B' : 'A';
      return role + ': ' + String(row.message || '').trim();
    }).join('\n')
  : '(primera interaccion)';

const profileBits = [];
if (customerData.id) profileBits.push('id:' + customerData.id);
if (profileCity) profileBits.push('ciudad:' + profileCity);
