          latitude,
          longitude,
          name: String(data.store_location_name || 'TechnoStore Salta').trim(),
          address: String(data.store_location_address || '').trim()
        }
      },
      wa_id: waId,
      message_type: 'location'
    }
  });
}

const selectedSticker = pickSticker();
const canUseFallbackSticker = !data.needs_human && intent !== 'complaint';
if (items.length > 0 && selectedSticker) {
  const mediaId = String(selectedSticker.media_id || '').trim();
  const stickerUrl = String(selectedSticker.sticker_url || '').trim();
  if (mediaId || /^https?:\/\//i.test(stickerUrl)) {
    items.push({
      json: {
        request_body: {
          messaging_product: 'whatsapp',
          to: waId,
          type: 'sticker',
          sticker: mediaId ? { id: mediaId } : { link: stickerUrl }
        },
        wa_id: waId,
        message_type: 'sticker',
        sticker_key: String(selectedSticker.sticker_key || '').trim(),
        sticker_mode: mediaId ? 'db_media_id' : 'db_link'
      }
    });
  }
} else if (items.length > 0 && canUseFallbackSticker && (defaultStickerId || defaultStickerUrl)) {
  items.push({
    json: {
      request_body: {
        messaging_product: 'whatsapp',
        to: waId,
        type: 'sticker',
        sticker: defaultStickerId ? { id: defaultStickerId } : { link: defaultStickerUrl }
      },
      wa_id: waId,
      message_type: 'sticker',
      sticker_mode: defaultStickerId ? 'env_id' : 'env_link'
    }
  });
}

return items;

